import crypto from 'node:crypto';
import { Request, Response, NextFunction } from 'express';

export function withEtag<T>(compute: (req: Request) => Promise<{ etag: string; payload: T } | null>) {
  return async (req: Request, res: Response, next: NextFunction) => {
    try {
      const result = await compute(req);
      if (!result) return res.status(404).json({ error: 'NOT_FOUND' });
      res.setHeader('ETag', `"${result.etag}"`);
      const ifNone = req.headers['if-none-match'];
      if (ifNone && ifNone.replace(/"/g, '') === result.etag) return res.status(304).end();
      res.json(result.payload);
    } catch (err) { next(err); }
  };
}

export function hashContent(parts: unknown[]): string {
  return crypto.createHash('sha1').update(parts.map(p => JSON.stringify(p)).join('|')).digest('hex');
}

import { OrderModel } from '../models/order.model';
