export const get = withEtag(async (req) => {
  const doc = await OrderModel.findById(req.params.id).lean();
  if (!doc) return null;
  return { etag: hashContent([doc._id, doc.updatedAt.getTime()]), payload: doc };
});

export const list = withEtag(async (req) => {
