import { Request, Response, NextFunction } from 'express';
import { ProductModel } from '../models/product.model';
import { z } from 'zod';
import { parser } from 'stream-json';
import { streamArray } from 'stream-json/streamers/StreamArray';

const productSchema = z.object({ name: z.string().min(1).max(200), price: z.number().nonnegative() });

export const bulkImport = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const errors: { row: number; reason: string }[] = [];
    const batch: { name: string; price: number }[] = [];
    let processed = 0; let inserted = 0;
    const flush = async () => {
      if (batch.length === 0) return;
      const docs = batch.splice(0);
      try { await ProductModel.insertMany(docs, { ordered: false }); inserted += docs.length; }
      catch { /* per-doc error tracking would require write concern handling */ }
    };
    const pipeline = req.pipe(parser()).pipe(streamArray());
    for await (const { key, value } of pipeline as any as AsyncIterable<{ key: number; value: unknown }>) {
      const parsed = productSchema.safeParse(value);
      if (!parsed.success) { errors.push({ row: key, reason: parsed.error.issues.map(i => i.message).join('; ') }); processed++; continue; }
      batch.push(parsed.data);
      processed++;
      if (batch.length >= 500) await flush();
    }
    await flush();
    res.json({ processed, inserted, errors });
  } catch (err) { next(err); }
};

