export const streamSearch = async (req: Request, res: Response, next: NextFunction) => {
  try {
    res.setHeader('Content-Type', 'text/event-stream');
    res.setHeader('Cache-Control', 'no-cache');
    res.setHeader('Connection', 'keep-alive');
    res.flushHeaders();
    const q = String(req.query.q ?? '');
    if (!q) { res.write('event: done\ndata: {}\n\n'); return res.end(); }
    const cursor = CodeModel.find({ $text: { $search: q } }).limit(200).cursor();
    let count = 0;
    let aborted = false;
    req.on('close', () => { aborted = true; cursor.close().catch(() => {}); });
    for await (const doc of cursor) {
      if (aborted) break;
      res.write(`event: result\ndata: ${JSON.stringify(doc)}\n\n`);
      count++;
      if (count % 20 === 0) await new Promise(r => setImmediate(r));
    }
    if (!aborted) { res.write(`event: done\ndata: ${JSON.stringify({ count })}\n\n`); res.end(); }
  } catch (err) { next(err); }
};

import { useEffect, useRef, useState } from 'react';

type Result = { _id: string; path: string; snippet: string };

export function useStreamSearch(query: string) {
  const [results, setResults] = useState<Result[]>([]);
  const [loading, setLoading] = useState(false);
  const esRef = useRef<EventSource | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    if (!query) { setResults([]); return; }
    debounceRef.current = setTimeout(() => {
      esRef.current?.close();
      setResults([]); setLoading(true);
      const es = new EventSource(`/api/search/stream?q=${encodeURIComponent(query)}`);
      esRef.current = es;
      es.addEventListener('result', (e) => setResults(prev => [...prev, JSON.parse((e as MessageEvent).data)]));
      es.addEventListener('done', () => { setLoading(false); es.close(); });
      es.onerror = () => { setLoading(false); es.close(); };
    }, 150);
    return () => { if (debounceRef.current) clearTimeout(debounceRef.current); esRef.current?.close(); };
  }, [query]);

  return { results, loading };
}

