type RoomMeta = { id: string; name: string; hvacZone: string; occupancy: number };

function Building({ url, isolatedFloor, onPick }: { url: string; isolatedFloor: number | null; onPick: (roomId: string) => void }) {
  const { scene } = useGLTF(url);

  useEffect(() => {
    scene.traverse(obj => {
      const m = obj as THREE.Mesh;
      if (!m.isMesh) return;
      const match = /^floor-(\d+)\.room-/.exec(obj.name);
      const floor = match ? Number(match[1]) : null;
      const mat = m.material as THREE.MeshStandardMaterial;
      if (isolatedFloor !== null && floor !== isolatedFloor) {
        mat.transparent = true; mat.opacity = 0.1; mat.depthWrite = false;
      } else {
        mat.transparent = false; mat.opacity = 1; mat.depthWrite = true;
      }
    });
  }, [scene, isolatedFloor]);

  return <primitive object={scene} onClick={(e: ThreeEvent<MouseEvent>) => { e.stopPropagation(); if ((e.object as THREE.Mesh).name) onPick((e.object as THREE.Mesh).name); }} />;
}

export function BuildingViewer({ url, buildingId }: { url: string; buildingId: string }) {
  const [isolated, setIsolated] = useState<number | null>(null);
  const [meta, setMeta] = useState<RoomMeta | null>(null);

  const onPick = async (roomName: string) => {
    const r = await fetch(`/api/buildings/${buildingId}/rooms/${encodeURIComponent(roomName)}`).then(r => r.json()) as RoomMeta;
    setMeta(r);
  };

  return (
    <div className="flex h-screen">
      <div className="flex-1">
        <Canvas camera={{ position: [50, 30, 50], fov: 50 }} dpr={[1, 2]}>
          <ambientLight intensity={0.5} />
          <directionalLight position={[20, 50, 30]} intensity={0.8} />
          <Suspense fallback={null}><Building url={url} isolatedFloor={isolated} onPick={onPick} /></Suspense>
          <OrbitControls />
        </Canvas>
      </div>
      <aside className="w-80 p-4 bg-white space-y-3">
        <div>
          <div className="text-sm font-medium">Floor</div>
          <div className="flex gap-1">{[null, 1, 2, 3, 4, 5].map(f => <button key={String(f)} onClick={() => setIsolated(f)} className={`px-2 py-1 rounded border ${isolated === f ? 'bg-black text-white' : ''}`}>{f === null ? 'All' : f}</button>)}</div>
        </div>
        {meta && (
          <div className="border-t pt-2">
            <div className="font-medium">{meta.name}</div>
            <div className="text-sm text-gray-500">HVAC: {meta.hvacZone}</div>
            <div className="text-sm text-gray-500">Occupancy: {meta.occupancy}</div>
