import { z } from 'zod';
import { endpoints, type EndpointName } from '../../shared/api/endpoints';

type ExtractParams<S extends string> = S extends `${string}:${infer P}/${infer Rest}` ? P | ExtractParams<Rest> : S extends `${string}:${infer P}` ? P : never;
type PathOnly<E extends EndpointName> = E extends `${string} ${infer P}` ? P : never;

function buildPath<E extends EndpointName>(name: E, params: Record<string, string>): string {
  const path = (name as string).split(' ')[1];
  return path.replace(/:([a-zA-Z]+)/g, (_, key) => encodeURIComponent(params[key]));
}

export async function rpc<E extends EndpointName>(
  name: E,
  args: (typeof endpoints)[E] extends { params: infer P } ? { params: z.infer<P & z.ZodTypeAny> } : Record<string, never>
         & ((typeof endpoints)[E] extends { body: infer B } ? { body: z.infer<B & z.ZodTypeAny> } : Record<string, never>)
): Promise<z.infer<(typeof endpoints)[E]['response']>> {
  const [method, _] = (name as string).split(' ');
  const url = buildPath(name, (args as { params?: Record<string, string> }).params ?? {});
  const res = await fetch(url, { method, credentials: 'include', headers: { 'content-type': 'application/json' }, body: (args as { body?: unknown }).body ? JSON.stringify((args as { body: unknown }).body) : undefined });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return endpoints[name].response.parse(await res.json()) as never;
}

