import { OpenApiGeneratorV31, OpenAPIRegistry } from '@asteasolutions/zod-to-openapi';
import { endpoints } from '../../shared/api/endpoints';

export function generateOpenApiSpec() {
  const registry = new OpenAPIRegistry();
  for (const [name, def] of Object.entries(endpoints)) {
    const [method, path] = name.split(' ');
    const oasPath = path.replace(/:([a-zA-Z]+)/g, '{$1}');
    registry.registerPath({
      method: method.toLowerCase() as 'get'|'post',
      path: oasPath,
      request: {
        params: 'params' in def ? def.params : undefined,
        body: 'body' in def ? { content: { 'application/json': { schema: def.body } } } : undefined
      },
      responses: {
        200: { description: 'OK', content: { 'application/json': { schema: def.response } } }
      }
    });
  }
  const gen = new OpenApiGeneratorV31(registry.definitions);
  return gen.generateDocument({
    openapi: '3.1.0',
    info: { title: 'API', version: '1.0.0' },
    servers: [{ url: 'https://api.example.com' }]
  });
}

