type Atom = { id: string; element: string; pos: [number, number, number]; residue: number; chain: string; isCa: boolean };

const ELEMENT_COLOR: Record<string, string> = { C: '#666', N: '#3b82f6', O: '#ef4444', S: '#f59e0b' };

function Atoms({ atoms, onPick, selected }: { atoms: Atom[]; onPick: (a: Atom) => void; selected: Set<string> }) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const tempMat = new THREE.Matrix4();
  const tempCol = new THREE.Color();

  useMemo(() => {
    const mesh = meshRef.current; if (!mesh) return;
    atoms.forEach((a, i) => {
      tempMat.setPosition(a.pos[0], a.pos[1], a.pos[2]);
      mesh.setMatrixAt(i, tempMat);
      const baseColor = ELEMENT_COLOR[a.element] ?? '#aaa';
      tempCol.set(selected.has(a.id) ? '#fcd34d' : baseColor);
      mesh.setColorAt(i, tempCol);
    });
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
    mesh.count = atoms.length;
  }, [atoms, selected]);

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, 10000]} onClick={(e: ThreeEvent<MouseEvent>) => { if (e.instanceId !== undefined) onPick(atoms[e.instanceId]); }}>
      <sphereGeometry args={[0.35, 12, 8]} />
      <meshStandardMaterial />
    </instancedMesh>
  );
}

function Ribbon({ atoms }: { atoms: Atom[] }) {
  const ca = useMemo(() => atoms.filter(a => a.isCa).map(a => new THREE.Vector3(...a.pos)), [atoms]);
  if (ca.length < 2) return null;
  const curve = new THREE.CatmullRomCurve3(ca);
  const tube = new THREE.TubeGeometry(curve, ca.length * 4, 0.3, 8, false);
  return <mesh geometry={tube}><meshStandardMaterial color="#a5b4fc" side={THREE.DoubleSide} /></mesh>;
}

export function MoleculeViewer({ atoms }: { atoms: Atom[] }) {
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [picked, setPicked] = useState<Atom[]>([]);
  const onPick = (a: Atom) => {
    setSelected(prev => { const n = new Set(prev); n.add(a.id); return n; });
    setPicked(prev => [...prev, a].slice(-2));
  };
