import { io, Socket } from 'socket.io-client';

type QueuedEmit = { event: string; args: unknown[]; queueable: boolean };
export type ConnectionState = 'connecting' | 'connected' | 'disconnected';

export class ReconnectingSocket {
  private socket: Socket;
  private queue: QueuedEmit[] = [];
  private listeners = new Set<(s: ConnectionState) => void>();
  private state: ConnectionState = 'connecting';
  private maxQueue = 100;

  constructor(opts: { url: string; namespace?: string; auth?: () => Record<string, unknown> }) {
    this.socket = io(`${opts.url}${opts.namespace ?? ''}`, {
      transports: ['websocket'],
      auth: opts.auth ? opts.auth() : undefined,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 30_000,
      randomizationFactor: 0.3,
      reconnectionAttempts: Infinity
    });
    this.socket.on('connect', () => { this.setState('connected'); this.drain(); });
    this.socket.on('disconnect', () => this.setState('disconnected'));
    this.socket.io.on('reconnect_attempt', () => this.setState('connecting'));
  }

  private setState(s: ConnectionState) { this.state = s; for (const l of this.listeners) l(s); }

  onState(l: (s: ConnectionState) => void): () => void {
    this.listeners.add(l); l(this.state);
    return () => { this.listeners.delete(l); };
  }

  emit(event: string, ...args: unknown[]) { this.emitWith({ event, args, queueable: true }); }

  emitEphemeral(event: string, ...args: unknown[]) { this.emitWith({ event, args, queueable: false }); }

  private emitWith(item: QueuedEmit) {
    if (this.state === 'connected') { this.socket.emit(item.event, ...item.args); return; }
    if (!item.queueable) return;
    if (this.queue.length >= this.maxQueue) {
      const idx = this.queue.findIndex(q => !q.queueable);
      if (idx >= 0) this.queue.splice(idx, 1);
      else this.queue.shift();
    }
    this.queue.push(item);
  }

  private drain() {
    while (this.queue.length && this.state === 'connected') {
      const item = this.queue.shift()!;
      this.socket.emit(item.event, ...item.args);
    }
  }

  on(event: string, listener: (...args: unknown[]) => void) { this.socket.on(event, listener as never); }
  off(event: string, listener: (...args: unknown[]) => void) { this.socket.off(event, listener as never); }
  close() { this.socket.disconnect(); this.queue = []; }
}

