type Rule = { value: boolean; rolloutPercent?: number; orgOverrides?: Record<string, boolean> };

let cache: Map<string, Rule> | null = null;
let cacheAt = 0;
const TTL_MS = 5000;

const sub = redis.duplicate();
sub.subscribe('flags:invalidate', () => { cache = null; cacheAt = 0; });

async function getRules(): Promise<Map<string, Rule>> {
  if (cache && Date.now() - cacheAt < TTL_MS) return cache;
  const entries = await redis.hGetAll('flags');
  cache = new Map(Object.entries(entries).map(([k, v]) => [k, JSON.parse(v) as Rule]));
  cacheAt = Date.now();
  return cache;
}

export async function getFlag(name: string, ctx: { orgId?: string } = {}): Promise<boolean> {
  const rules = await getRules();
  const rule = rules.get(name);
  if (!rule) return false;
  if (ctx.orgId && rule.orgOverrides?.[ctx.orgId] !== undefined) return rule.orgOverrides[ctx.orgId];
  return rule.value;
}

export async function setFlag(name: string, rule: Rule) {
  await redis.hSet('flags', name, JSON.stringify(rule));
  await redis.publish('flags:invalidate', name);
}

