import { Request, Response, NextFunction } from 'express';
import { UserModel } from '../models/user.model';
import { PasswordResetModel } from '../models/password-reset.model';
import { RefreshTokenModel } from '../models/refresh-token.model';
import crypto from 'node:crypto';
import bcrypt from 'bcrypt';
import { enqueue } from '../queue/enqueue';
import { redis } from '../infra/redis';
import { HttpError } from '../errors/http-error';
import { auditLog } from '../services/audit.service';

const RATE_LIMIT = 3;
const RATE_WINDOW_S = 3600;

function hashToken(t: string) { return crypto.createHash('sha256').update(t).digest('hex'); }

export const forgotPassword = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const email = String(req.body.email ?? '').toLowerCase();
    if (!email) return res.json({ ok: true });
    const key = `forgot:${email}`;
    const count = await redis.incr(key);
    if (count === 1) await redis.expire(key, RATE_WINDOW_S);
    if (count > RATE_LIMIT) return res.json({ ok: true });
    const user = await UserModel.findOne({ email });
    if (user) {
      const token = crypto.randomBytes(32).toString('base64url');
      await PasswordResetModel.create({ userId: user._id, tokenHash: hashToken(token), expiresAt: new Date(Date.now() + 15 * 60 * 1000), status: 'pending' });
      await enqueue.email({ to: email, template: 'reset', data: { url: `https://app.example.com/reset#${token}` } });
      await auditLog({ actorId: 'system', action: 'reset.requested', target: String(user._id) });
    }
    res.json({ ok: true });
  } catch (err) { next(err); }
};

export const resetPassword = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { token, newPassword } = req.body;
    if (typeof newPassword !== 'string' || newPassword.length < 12) throw new HttpError(400, 'WEAK_PASSWORD');
    const reset = await PasswordResetModel.findOne({ tokenHash: hashToken(token), status: 'pending' });
    if (!reset || reset.expiresAt < new Date()) throw new HttpError(404, 'INVALID_OR_EXPIRED');
    const user = await UserModel.findById(reset.userId);
    if (!user) throw new HttpError(404, 'INVALID_OR_EXPIRED');
    user.passwordHash = await bcrypt.hash(newPassword, 12);
    await user.save();
    reset.status = 'used';
    await reset.save();
    await RefreshTokenModel.updateMany({ userId: user._id, status: 'active' }, { $set: { status: 'revoked' } });
    await auditLog({ actorId: String(user._id), action: 'reset.completed', target: String(user._id) });
    res.json({ ok: true });
  } catch (err) { next(err); }
};

