export const httpDuration = new Histogram({
  name: 'http_request_duration_seconds',
  help: 'HTTP request duration',
  labelNames: ['method','route','status'],
  buckets: [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10]
});
export const httpErrors = new Counter({ name: 'http_errors_total', help: 'HTTP 5xx', labelNames: ['route'] });

export function metricsMiddleware(req: Request, res: Response, next: () => void) {
  const end = httpDuration.startTimer({ method: req.method });
  res.on('finish', () => {
    const route = req.route?.path ?? req.path;
    end({ route, status: String(res.statusCode) });
    if (res.statusCode >= 500) httpErrors.inc({ route });
  });
  next();
}

export function mountMetrics(app: express.Express) {
  app.get('/metrics', async (_req, res) => { res.setHeader('Content-Type', register.contentType); res.send(await register.metrics()); });
}

