import { io, Socket } from 'socket.io-client';

let socket: Socket | null = null;
function getSocket(token: string): Socket {
  if (!socket) socket = io('/', { auth: { token }, transports: ['websocket'] });
  return socket;
}

export class Channel {
  private listeners = new Map<string, Set<(...args: unknown[]) => void>>();
  constructor(private socket: Socket, private prefix: string) {}
  on(event: string, listener: (...args: unknown[]) => void) {
    const fullEvent = `${this.prefix}:${event}`;
    let set = this.listeners.get(fullEvent);
    if (!set) { set = new Set(); this.listeners.set(fullEvent, set); }
    set.add(listener);
    this.socket.on(fullEvent, listener as never);
    return () => { this.socket.off(fullEvent, listener as never); set!.delete(listener); };
  }
  emit(event: string, ...args: unknown[]) { this.socket.emit(`${this.prefix}:${event}`, ...args); }
  dispose() {
    for (const [event, set] of this.listeners) for (const l of set) this.socket.off(event, l as never);
    this.listeners.clear();
  }
}

export function getChannel(token: string, prefix: string): Channel { return new Channel(getSocket(token), prefix); }

import { useEffect, useState } from 'react';
import { getChannel, Channel } from '../../lib/shared-socket';

export function useChat(token: string) {
  const [messages, setMessages] = useState<{ id: string; text: string }[]>([]);
  useEffect(() => {
    const ch = getChannel(token, 'chat');
    const off = ch.on('message', (m: unknown) => setMessages(prev => [...prev, m as { id: string; text: string }]));
    return () => { off(); ch.dispose(); };
  }, [token]);
  return messages;
}

