import { createElement, ComponentType, useSyncExternalStore } from 'react';

type Entry = { id: string; Component: ComponentType<{ close: (result?: unknown) => void }>; props: Record<string, unknown>; resolve: (result?: unknown) => void };

let stack: Entry[] = [];
const listeners = new Set<() => void>();
function emit() { for (const l of listeners) l(); }

let counter = 0;

export function openModal<T = unknown>(Component: ComponentType<{ close: (result?: T) => void } & Record<string, unknown>>, props: Record<string, unknown> = {}): Promise<T | undefined> {
  return new Promise<T | undefined>(resolve => {
    const id = `m-${++counter}`;
    stack = [...stack, { id, Component: Component as ComponentType<{ close: (result?: unknown) => void }>, props, resolve: resolve as (r?: unknown) => void }];
    emit();
  });
}

function closeTop(result?: unknown) {
  const top = stack.at(-1);
  if (!top) return;
  stack = stack.slice(0, -1);
  emit();
  top.resolve(result);
}

export function ModalRoot() {
  const snap = useSyncExternalStore(l => { listeners.add(l); return () => { listeners.delete(l); }; }, () => stack);
  if (snap.length === 0) return null;
  return (
    <div className="fixed inset-0 z-50" onKeyDown={(e) => { if (e.key === 'Escape') closeTop(); }} tabIndex={-1}>
      {snap.map((entry, i) => (
        <div key={entry.id} className="fixed inset-0 bg-black/40 flex items-center justify-center" style={{ zIndex: 50 + i }} onClick={(e) => { if (e.target === e.currentTarget && i === snap.length - 1) closeTop(); }}>
          <div className="bg-white rounded p-4 max-w-md w-full">
            {createElement(entry.Component, { ...entry.props, close: (result: unknown) => { stack = stack.filter(s => s.id !== entry.id); emit(); entry.resolve(result); } })}
          </div>
        </div>
      ))}
    </div>
  );
}

