import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Plane } from '@react-three/drei';
import { Suspense, useEffect, useMemo, useRef } from 'react';
import * as THREE from 'three';
import { io } from 'socket.io-client';

type Vehicle = { id: string; x: number; z: number; tx: number; tz: number; color: number };

const vehicles = new Map<string, Vehicle>();

function Vehicles() {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const m = new THREE.Matrix4();
  const c = new THREE.Color();
  useFrame(() => {
    const mesh = meshRef.current; if (!mesh) return;
    let i = 0;
    for (const v of vehicles.values()) {
      v.x += (v.tx - v.x) * 0.15;
      v.z += (v.tz - v.z) * 0.15;
      m.setPosition(v.x, 0.5, v.z);
      mesh.setMatrixAt(i, m);
      c.set(v.color);
      mesh.setColorAt(i, c);
      i++;
    }
    mesh.count = i;
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
  });
  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, 600]}>
      <boxGeometry args={[0.6, 0.6, 1.2]} />
      <meshStandardMaterial />
    </instancedMesh>
  );
}

export function FleetMap3D({ token }: { token: string }) {
  useEffect(() => {
    const socket = io('/fleet', { auth: { token }, transports: ['websocket'] });
    socket.emit('fleet:hello', { sinceMs: Date.now() - 60_000 });
    socket.on('vehicle:update', (u: { id: string; x: number; z: number; color: number }) => {
      const existing = vehicles.get(u.id);
      if (!existing) vehicles.set(u.id, { id: u.id, x: u.x, z: u.z, tx: u.x, tz: u.z, color: u.color });
      else { existing.tx = u.x; existing.tz = u.z; existing.color = u.color; }
    });
    socket.on('vehicle:remove', ({ id }: { id: string }) => vehicles.delete(id));
    return () => { socket.disconnect(); };
  }, [token]);

  return (
    <div className="w-full h-screen">
      <Canvas camera={{ position: [0, 60, 80], fov: 50 }} dpr={[1, 2]}>
        <ambientLight intensity={0.6} />
        <directionalLight position={[20, 50, 20]} intensity={0.8} />
        <Plane args={[200, 200]} rotation={[-Math.PI / 2, 0, 0]}><meshStandardMaterial color="#cbd5e1" /></Plane>
        <Suspense fallback={null}><Vehicles /></Suspense>
        <OrbitControls maxPolarAngle={Math.PI / 2.2} />
      </Canvas>
    </div>
  );
}

import crypto from 'node:crypto';
import { kek } from './kek';
export async function encrypt(plain: string) {
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv('aes-256-gcm', await kek(), iv);
  const ct = Buffer.concat([cipher.update(plain, 'utf8'), cipher.final()]);
  return { iv: iv.toString('base64'), ct: ct.toString('base64'), tag: cipher.getAuthTag().toString('base64') };
}

import crypto from 'node:crypto';
import { kms } from '../infra/kms';

export type EncryptedSecret = { ct: string; iv: string; tag: string; encDek: string; tenantId: string; kekAlias: string };

export async function encryptForTenant(tenantId: string, plain: string): Promise<EncryptedSecret> {
  const dek = crypto.randomBytes(32);
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv('aes-256-gcm', dek, iv);
  const ct = Buffer.concat([cipher.update(plain, 'utf8'), cipher.final()]);
  const tag = cipher.getAuthTag();
  const kekAlias = `tenant/${tenantId}`;
  const { encrypted } = await kms.encryptWith(kekAlias, dek);
  return { ct: ct.toString('base64'), iv: iv.toString('base64'), tag: tag.toString('base64'), encDek: encrypted, tenantId, kekAlias };
}

export async function decryptForTenant(secret: EncryptedSecret): Promise<string> {
  const dek = await kms.decryptWith(secret.kekAlias, secret.encDek);
  const decipher = crypto.createDecipheriv('aes-256-gcm', dek, Buffer.from(secret.iv, 'base64'));
  decipher.setAuthTag(Buffer.from(secret.tag, 'base64'));
  return Buffer.concat([decipher.update(Buffer.from(secret.ct, 'base64')), decipher.final()]).toString('utf8');
}

import { SecretModel } from '../models/secret.model';
import { encryptForTenant, decryptForTenant } from '../crypto/tenant-secrets';

export const secretService = {
  async store(tenantId: string, name: string, plain: string) {
    const enc = await encryptForTenant(tenantId, plain);
    await SecretModel.updateOne({ tenantId, name }, { $set: enc }, { upsert: true });
  },
  async load(tenantId: string, name: string): Promise<string | null> {
    const doc = await SecretModel.findOne({ tenantId, name });
    if (!doc) return null;
    return decryptForTenant(doc as any);
  }
};

